const { readFileSync } = require('node:fs')
const token = readFileSync('/root/.supabase/access-token','utf8').trim()
const project = 'qsllyeztdwjgirsysgai'
function dxRows(sql) { const out = execFileSync('docker', ['exec','directus-db-nzli85mk3luzb6u7cnq5fidu','psql','-U','directus','-d','directus','-At','-c', `select coalesce(jsonb_agg(to_jsonb(x)), '[]'::jsonb) from (${sql}) x`], {encoding:'utf8', maxBuffer: 100 * 1024 * 1024}); return JSON.parse(out.trim() || '[]') }
async function supa(sql) { const res = await fetch(`https://api.supabase.com/v1/projects/${project}/database/query`, { method:'POST', headers:{Authorization:`Bearer ${token}`,'Content-Type':'application/json'}, body: JSON.stringify({query: sql}) }); const txt = await res.text(); if (!res.ok) throw new Error(`${res.status} ${txt}\nSQL:\n${sql.slice(0,1000)}`); try { return JSON.parse(txt) } catch { return txt } }
function litJson(rows) { return `$crmjson$${JSON.stringify(rows).replaceAll('$crmjson$', '$crm_json$')}$crmjson$::jsonb` }
function esc(s) { return String(s).replaceAll("'", "''") }
async function batches(name, baseSql, size, fn) { let offset=0,total=0; for (;;) { const rows=dxRows(`${baseSql} limit ${size} offset ${offset}`); if (!rows.length) break; await fn(rows); total+=rows.length; offset+=size; console.log(`${name}: ${total}`) } return total }
async function main() {
  const users = dxRows(`select id::text, email, first_name, last_name, status, provider, external_identifier from directus_users where email is not null order by email`)
  await supa(`with src as (select * from jsonb_to_recordset(${litJson(users)}) as x(id text, email text, first_name text, last_name text, status text, provider text, external_identifier text))
    insert into app.profile (id, email, display_name, provider, external_identifier, status, source_refs)
    select id::uuid, email::extensions.citext, nullif(trim(concat_ws(' ', first_name, last_name)), ''), provider, external_identifier, case when status='active' then 'active'::app.entity_status else 'inactive'::app.entity_status end, jsonb_build_object('directus_user_id', id, 'source', 'directus') from src
    where not exists (select 1 from app.profile p where lower(p.email::text)=lower(src.email))
    on conflict (id) do update set email=excluded.email, display_name=excluded.display_name, provider=excluded.provider, external_identifier=excluded.external_identifier, source_refs=app.profile.source_refs || excluded.source_refs, updated_at=now();
    with src as (select * from jsonb_to_recordset(${litJson(users)}) as x(id text, email text, first_name text, last_name text, status text, provider text, external_identifier text))
    update app.profile p set source_refs = p.source_refs || jsonb_build_object('directus_user_id', src.id, 'directus_email', src.email), updated_at=now() from src where lower(p.email::text)=lower(src.email);
    insert into app.user_role (profile_id, role_id) select p.id, r.id from app.profile p cross join app.role r where lower(p.email::text) = 'albert@popcre.com' and r.slug = 'administrator' on conflict (profile_id, role_id) do update set revoked_at=null;
    insert into app.app_access (profile_id, app) select p.id, 'crm'::app.app_name from app.profile p where lower(p.email::text) like '%@popcre.com' on conflict (profile_id, app) do update set revoked_at=null;`)

  const factories = dxRows(`select id::text, name, capabilities, china_team_contact, external_id, external_source, location, contact_name, contact_email, notes from factory order by id`)
  await supa(`with src as (select * from jsonb_to_recordset(${litJson(factories)}) as x(id text, name text, capabilities text, china_team_contact text, external_id text, external_source text, location text, contact_name text, contact_email text, notes text))
    insert into core.factory (id, name, code, status, country, metadata)
    select id::uuid, coalesce(nullif(name,''), 'Unnamed factory'), coalesce(nullif(external_id,''), 'directus:' || id), 'active', location, jsonb_strip_nulls(jsonb_build_object('capabilities', capabilities, 'china_team_contact', china_team_contact, 'contact_name', contact_name, 'contact_email', contact_email, 'notes', notes, 'external_id', external_id, 'external_source', external_source)) from src
    on conflict (id) do update set name=excluded.name, code=excluded.code, country=excluded.country, metadata=core.factory.metadata || excluded.metadata, updated_at=now();`)

  async function importCompanies(sourceTable) {
    return batches(sourceTable, `select id::text, name, aliases, resale_restriction, notes, external_id, external_source, domain, routing_aliases, so_patterns, customer_status, chain_type, primary_salesperson::text, account_owner::text, logo_url from ${sourceTable} order by id`, 500, async rows => {
      await supa(`with src as (select * from jsonb_to_recordset(${litJson(rows)}) as x(id text, name text, aliases text, resale_restriction boolean, notes text, external_id text, external_source text, domain text, routing_aliases text, so_patterns text, customer_status text, chain_type text, primary_salesperson text, account_owner text, logo_url text)), mapped as (select src.*, (select p.id from app.profile p where p.source_refs->>'directus_user_id' = src.primary_salesperson limit 1) as primary_salesperson_profile_id, (select p.id from app.profile p where p.source_refs->>'directus_user_id' = src.account_owner limit 1) as account_owner_profile_id from src)
        insert into core.company (id, name, company_type, status, domain, metadata, customer_status, chain_type, routing_aliases, so_patterns, primary_salesperson_profile_id, account_owner_profile_id)
        select id::uuid, coalesce(nullif(name,''), 'Unnamed account'), 'customer', 'active', nullif(domain,''), jsonb_strip_nulls(jsonb_build_object('aliases', aliases, 'resale_restriction', resale_restriction, 'notes', notes, 'logo_url', logo_url, 'source_table', '${esc(sourceTable)}')), coalesce(nullif(customer_status,''), 'UNASSIGNED'), chain_type, routing_aliases, so_patterns, primary_salesperson_profile_id, account_owner_profile_id from mapped
        on conflict (id) do update set name=excluded.name, domain=excluded.domain, metadata=core.company.metadata || excluded.metadata, customer_status=excluded.customer_status, chain_type=excluded.chain_type, routing_aliases=excluded.routing_aliases, so_patterns=excluded.so_patterns, primary_salesperson_profile_id=coalesce(excluded.primary_salesperson_profile_id, core.company.primary_salesperson_profile_id), account_owner_profile_id=coalesce(excluded.account_owner_profile_id, core.company.account_owner_profile_id), updated_at=now();
        with src as (select * from jsonb_to_recordset(${litJson(rows)}) as x(id text, name text, aliases text, resale_restriction boolean, notes text, external_id text, external_source text, domain text, routing_aliases text, so_patterns text, customer_status text, chain_type text, primary_salesperson text, account_owner text, logo_url text))
        insert into core.company_source_ref (company_id, source_system, source_table, source_id, source_code, source_name, raw) select id::uuid, 'directus', '${esc(sourceTable)}', id, external_id, name, to_jsonb(src) from src on conflict (source_system, source_table, source_id) do update set company_id=excluded.company_id, source_code=excluded.source_code, source_name=excluded.source_name, raw=excluded.raw;`)
    })
  }
  await importCompanies('retailer')
  await importCompanies('ingested_domains')

  async function importContacts(sourceTable) {
    return batches(sourceTable, `select id::text, name, retailer::text, email, samples_required, external_id, external_source, first_name, last_name, phone, job_title, contact_type, scope, department::text from ${sourceTable} order by id`, 500, async rows => {
      await supa(`with src as (select * from jsonb_to_recordset(${litJson(rows)}) as x(id text, name text, retailer text, email text, samples_required boolean, external_id text, external_source text, first_name text, last_name text, phone text, job_title text, contact_type text, scope text, department text))
        insert into core.contact (id, full_name, first_name, last_name, email, phone, title, status, metadata)
        select id::uuid, coalesce(nullif(name,''), nullif(trim(concat_ws(' ', first_name, last_name)), ''), email), first_name, last_name, nullif(email,'')::extensions.citext, phone, job_title, 'active', jsonb_strip_nulls(jsonb_build_object('samples_required', samples_required, 'source_table', '${esc(sourceTable)}')) from src
        on conflict (id) do update set full_name=excluded.full_name, first_name=excluded.first_name, last_name=excluded.last_name, email=excluded.email, phone=excluded.phone, title=excluded.title, metadata=core.contact.metadata || excluded.metadata, updated_at=now();
        with src as (select * from jsonb_to_recordset(${litJson(rows)}) as x(id text, name text, retailer text, email text, samples_required boolean, external_id text, external_source text, first_name text, last_name text, phone text, job_title text, contact_type text, scope text, department text))
        insert into core.contact_source_ref (contact_id, source_system, source_table, source_id, source_email, raw) select id::uuid, 'directus', '${esc(sourceTable)}', id, nullif(email,'')::extensions.citext, to_jsonb(src) from src on conflict (source_system, source_table, source_id) do update set contact_id=excluded.contact_id, source_email=excluded.source_email, raw=excluded.raw;
        with src as (select * from jsonb_to_recordset(${litJson(rows)}) as x(id text, name text, retailer text, email text, samples_required boolean, external_id text, external_source text, first_name text, last_name text, phone text, job_title text, contact_type text, scope text, department text)), valid as (select src.* from src join core.company c on c.id = src.retailer::uuid where src.retailer is not null)
        insert into core.contact_company (contact_id, company_id, relationship_type, title, is_primary, metadata, contact_type, scope, crm_department_id)
        select id::uuid, retailer::uuid, 'buyer', job_title, true, jsonb_strip_nulls(jsonb_build_object('samples_required', samples_required, 'source_table', '${esc(sourceTable)}')), contact_type, scope, case when department is not null and exists (select 1 from crm.department d where d.id = department::uuid) then department::uuid else null end from valid
        on conflict (contact_id, company_id, relationship_type) do update set title=excluded.title, is_primary=true, metadata=core.contact_company.metadata || excluded.metadata, contact_type=excluded.contact_type, scope=excluded.scope, crm_department_id=coalesce(excluded.crm_department_id, core.contact_company.crm_department_id);`)
    })
  }
  await importContacts('buyer')
  await importContacts('ingested_contact')

  const summary = await supa(`select 'core.company' as item, count(*)::bigint as rows from core.company union all select 'core.contact', count(*) from core.contact union all select 'core.contact_company', count(*) from core.contact_company union all select 'core.company_source_ref', count(*) from core.company_source_ref where source_system='directus' union all select 'core.contact_source_ref', count(*) from core.contact_source_ref where source_system='directus' union all select 'core.factory', count(*) from core.factory union all select 'api.crm_account_list', count(*) from api.crm_account_list union all select 'api.crm_contact_list', count(*) from api.crm_contact_list union all select 'app.profile', count(*) from app.profile union all select 'app.app_access crm', count(*) from app.app_access where app='crm' and revoked_at is null order by item;`)
  console.log(JSON.stringify(summary, null, 2))
}
main().catch(err => { console.error(err); process.exit(1) })
